import json
import logging
import os
from typing import Any, Dict, Optional

import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent


app = func.FunctionApp()

STORAGE_ACCOUNT_URL = os.environ["STORAGE_ACCOUNT_URL"]
COSMOS_ENDPOINT = os.environ["COSMOS_ENDPOINT"]
COSMOS_DATABASE_NAME = os.environ.get("COSMOS_DATABASE_NAME", "mvp-db")
COSMOS_CONTAINER_NAME = os.environ.get("COSMOS_CONTAINER_NAME", "results")
EVENT_GRID_TOPIC_ENDPOINT = os.environ["EVENT_GRID_TOPIC_ENDPOINT"]
EVENT_GRID_EVENT_TYPE = os.environ.get("EVENT_GRID_EVENT_TYPE", "Contoso.FileProcessed")
EVENT_GRID_SUBJECT_PREFIX = os.environ.get("EVENT_GRID_SUBJECT_PREFIX", "files")
MANAGED_IDENTITY_CLIENT_ID = os.environ.get("MANAGED_IDENTITY_CLIENT_ID")

credential = DefaultAzureCredential(managed_identity_client_id=MANAGED_IDENTITY_CLIENT_ID)

cosmos_client = CosmosClient(COSMOS_ENDPOINT, credential=credential)
database = cosmos_client.create_database_if_not_exists(id=COSMOS_DATABASE_NAME)
container = database.create_container_if_not_exists(
    id=COSMOS_CONTAINER_NAME,
    partition_key=PartitionKey(path="/partitionKey"),
)

event_grid_client = EventGridPublisherClient(
    endpoint=EVENT_GRID_TOPIC_ENDPOINT,
    credential=credential,
)


def _parse_blob_trigger_path(blob_trigger: str) -> Dict[str, str]:
    parts = blob_trigger.split("/", 1)
    container_name = parts[0]
    blob_name = parts[1] if len(parts) > 1 else ""
    return {"container_name": container_name, "blob_name": blob_name}


def _read_blob_text(container_name: str, blob_name: str) -> str:
    blob_client = BlobClient(
        account_url=STORAGE_ACCOUNT_URL,
        container_name=container_name,
        blob_name=blob_name,
        credential=credential,
    )
    return blob_client.download_blob().readall().decode("utf-8")


def _process_content(content: str, blob_name: str) -> Dict[str, Any]:
    line_count = len(content.splitlines())
    char_count = len(content)
    word_count = len(content.split())
    return {
        "id": blob_name.replace("/", "_"),
        "partitionKey": "processed-files",
        "blobName": blob_name,
        "lineCount": line_count,
        "wordCount": word_count,
        "charCount": char_count,
        "preview": content[:500],
        "status": "processed",
    }


def _write_to_cosmos(document: Dict[str, Any]) -> Dict[str, Any]:
    return container.upsert_item(document)


def _send_event(document: Dict[str, Any]) -> None:
    event = EventGridEvent(
        subject=f"{EVENT_GRID_SUBJECT_PREFIX}/{document['blobName']}",
        event_type=EVENT_GRID_EVENT_TYPE,
        data_version="1.0",
        data={
            "id": document["id"],
            "blobName": document["blobName"],
            "status": document["status"],
            "lineCount": document["lineCount"],
            "wordCount": document["wordCount"],
            "charCount": document["charCount"],
        },
    )
    event_grid_client.send([event])


@app.function_name(name="ProcessBlobToCosmosAndNotify")
@app.blob_trigger(
    arg_name="inputblob",
    path="incoming/{name}",
    connection="AzureWebJobsStorage",
)
def main(inputblob: func.InputStream) -> None:
    logging.info("Processing blob: %s, size: %s bytes", inputblob.name, inputblob.length)

    path_info = _parse_blob_trigger_path(inputblob.name)
    container_name = path_info["container_name"]
    blob_name = path_info["blob_name"]

    try:
        content = _read_blob_text(container_name, blob_name)
        document = _process_content(content, blob_name)
        saved = _write_to_cosmos(document)
        _send_event(saved)
        logging.info("Successfully processed blob: %s", blob_name)
    except Exception as exc:
        logging.exception("Failed processing blob %s: %s", blob_name, str(exc))
        raise


